export function ExecutiveDashboard() {
  const [data, setData] = useState<DashboardData | null>(null);
  const [loading, setLoading] = useState(true);
  const [preset, setPreset] = useState<DateRangePreset>("month");
  const [exporting, setExporting] = useState(false);
  const [reportType, setReportType] = useState<ReportType>("monthly");

  useEffect(() => {
    let active = true;
    getDashboardAction({ preset }).then((result) => {
      if (!active) return;
      setData(result);
      setLoading(false);
    });
    return () => { active = false };
  }, [preset]);

  const handlePresetChange = (newPreset: DateRangePreset) => {
    setLoading(true);
    setPreset(newPreset);
  };

  const handleExport = async (format: ExportFormat) => {
    setExporting(true);
    try {
      const result = await exportReportAction({ reportType, format, preset });
      if (result.success && result.data) {
        const blob = new Blob([result.data], { type: result.mime });
        const url = URL.createObjectURL(blob);
        const link = document.createElement("a");
        link.href = url;
        link.download = `${reportType}-report.${result.ext}`;
        link.click();
        URL.revokeObjectURL(url);
        toast.success("تم تصدير التقرير");
      } else {
        toast.error(result.error ?? "فشل في التصدير");
      }
    } finally {
      setExporting(false);
